<script lang="ts">
  import { onDestroy } from 'svelte';
  import { api, openJobSocket, setToken, type Agent, type Artifact, type EventEnvelope, type JobKind, type Json, type ServiceJob } from './api';

  type Claims = { sub?: string; user_id?: string; tenant_id?: string; tenantId?: string; roles?: string[] | string; [key: string]: unknown };
  const states = ['accepted','queued','running','waiting_approval','waiting_clarification','cancelling','succeeded','failed','cancelled'];
  const kinds: JobKind[] = ['run','chat','swarm','orchestration'];
  let jwt = '', tokenInput = '', claims: Claims | null = null;
  let workspace: 'user' | 'admin' = 'user', view: 'jobs' | 'submit' | 'overview' | 'tenants' | 'users' = 'jobs';
  let jobs: ServiceJob[] = [], total = 0, offset = 0, limit = 20, kindFilter = '', stateFilter = '', tenantFilter = '', ownerFilter = '', loading = false;
  let selected: ServiceJob | null = null, events: EventEnvelope[] = [], artifacts: Artifact[] = [], runLinks: unknown = null, audit: unknown = null;
  let agents: Agent[] = [], error = '', notice = '', diagnostics = false, socketState = 'offline', socket: WebSocket | null = null, reconnect: ReturnType<typeof setTimeout> | null = null;
  let submitKind: JobKind = 'run', primaryAgent = '', otherAgents: string[] = [], prompt = '', conversationId = '', jsonInput = '', idempotencyKey = '';
  let availableArtifacts: Artifact[] = [], selectedFileRefs: string[] = [], loadingArtifacts = false, artifactOffset = 0, artifactLimit = 50, artifactTotal = 0;
  let controlText = '', overview: unknown = null, tenants: unknown[] = [], users: unknown[] = [], userTenantFilter = '';

  function decode(value: string): Claims | null { try { return JSON.parse(decodeURIComponent(Array.from(atob(value.split('.')[1].replace(/-/g,'+').replace(/_/g,'/'))).map(c => `%${c.charCodeAt(0).toString(16).padStart(2,'0')}`).join(''))); } catch { return null; } }
  function roles() { const value = claims?.roles; return Array.isArray(value) ? value : typeof value === 'string' ? value.split(/[ ,]/).filter(Boolean) : []; }
  function isAdmin() { return roles().includes('platform_admin'); }
  function signIn(value = tokenInput) { error = ''; const decoded = decode(value.trim()); if (!decoded) { error = 'This token does not contain a readable JWT payload.'; return; } jwt = value.trim(); claims = decoded; setToken(jwt); tokenInput = ''; refreshJobs(); loadAgents(); }
  function signOut() { socket?.close(); jwt = ''; claims = null; selected = null; jobs = []; setToken(''); workspace = 'user'; view = 'jobs'; }
  function fail(reason: unknown) { error = reason instanceof Error ? reason.message : String(reason); }
  async function refreshJobs() { loading = true; error = ''; try { const page = await api.jobs({kind:kindFilter,state:stateFilter,tenantId:workspace==='admin'?tenantFilter:undefined,ownerUserId:workspace==='admin'?ownerFilter:undefined,limit,offset},workspace==='admin'); jobs=page.items; total=page.total; } catch(e){fail(e)} finally{loading=false} }
  async function loadAgents() { try { agents=(await api.agents()).items; if(!primaryAgent&&agents[0]) primaryAgent=agents[0].id; } catch(e){fail(e)} }
  async function loadAvailableArtifacts() { loadingArtifacts=true;try{const page=await api.availableArtifacts(artifactLimit,artifactOffset);availableArtifacts=page.items;artifactTotal=page.total;}catch(e){fail(e)}finally{loadingArtifacts=false} }
  function fmt(value: unknown) { return JSON.stringify(value, null, 2); }
  function when(value?: string) { return value ? new Date(value).toLocaleString() : '—'; }
  function lastSequence() { return events.reduce((max,event)=>Math.max(max,event.sequence),0); }
  async function replay() { if(!selected)return; try { const incoming=await api.events(selected.id,lastSequence(),workspace==='admin'); const known=new Set(events.map(e=>e.sequence)); events=[...events,...incoming.filter(e=>!known.has(e.sequence))].sort((a,b)=>a.sequence-b.sequence); } catch(e){fail(e)} }
  function connect() { if(!selected)return; socket?.close(); if(reconnect)clearTimeout(reconnect); const id=selected.id; socketState='connecting'; socket=openJobSocket(jwt,id,lastSequence(),message=>{ if(message.type==='event'&&message.event){ const event=message.event as EventEnvelope; if(!events.some(e=>e.sequence===event.sequence))events=[...events,event]; socketState='live'; } else if(message.type==='job'&&message.job)selected=message.job as ServiceJob; else if(message.type==='error')socketState='replaying'; },()=>{ socketState='replaying'; replay(); if(selected?.id===id) reconnect=setTimeout(connect,2000); }); }
  async function selectJob(job: ServiceJob) { selected=job; events=[]; artifacts=[]; runLinks=null; audit=null; error=''; try { [selected,events,artifacts]=await Promise.all([api.job(job.id,workspace==='admin'),api.events(job.id,0,workspace==='admin'),api.artifacts(job.id,workspace==='admin')]); if(workspace==='admin'){[runLinks,audit]=await Promise.all([api.auxiliary(job.id,'run-links'),api.auxiliary(job.id,'audit')]);socketState='HTTP replay';}else connect(); } catch(e){fail(e)} }
  function toggleAgent(id:string){otherAgents=otherAgents.includes(id)?otherAgents.filter(value=>value!==id):[...otherAgents,id]}
  function toggleFileRef(id:string){selectedFileRefs=selectedFileRefs.includes(id)?selectedFileRefs.filter(value=>value!==id):[...selectedFileRefs,id]}
  async function submit() { error=''; try { let body: Json; const input=jsonInput.trim()?JSON.parse(jsonInput):undefined;const files:Record<string,Json>={};if(selectedFileRefs.length)files.fileRefs=selectedFileRefs.map(artifactId=>({artifactId})); if(submitKind==='run') body={schemaVersion:1,agentId:primaryAgent,goal:prompt,...(input===undefined?{}:{input}),...files}; else if(submitKind==='chat') body={schemaVersion:1,agentId:primaryAgent,message:prompt,...(conversationId?{conversationId}:{}),...files}; else if(submitKind==='swarm') body={schemaVersion:1,coordinatorAgentId:primaryAgent,workerAgentIds:otherAgents,objective:prompt,...files}; else body={schemaVersion:1,orchestratorAgentId:primaryAgent,agentIds:otherAgents,objective:prompt,...files}; const result=await api.submit(submitKind,body,idempotencyKey||undefined); notice=`Job ${result.jobId} accepted`;selectedFileRefs=[]; view='jobs'; await refreshJobs(); } catch(e){fail(e)} }
  async function control(action:string,body:Json={}) { if(!selected)return; error=''; try { selected=await api.control(selected.id,action,body,workspace==='admin',idempotencyKey||undefined); notice=`${action} requested`; controlText=''; await refreshJobs(); } catch(e){fail(e)} }
  async function loadAdmin(resource:'overview'|'tenants'|'users'){ error=''; try { const value=await api.admin<unknown>(resource,resource==='users'?{tenantId:userTenantFilter||undefined,limit:200,offset:0}:{}); if(resource==='overview')overview=value; else { const rows=Array.isArray(value)?value:(value as {items?:unknown[]}).items||[]; if(resource==='tenants')tenants=rows; else users=rows; } }catch(e){fail(e)} }
  async function downloadQuarantined(artifact:Artifact){if(!selected)return;const warning=`${artifact.filename} was quarantined because it may contain active or unsafe content. Download only if you trust it. Opening it may run code or contact external services. Continue?`;if(!window.confirm(warning))return;await api.download(selected.id,artifact,true)}
  function controlAllowed(action:string){if(!selected)return false;const allowed:Record<string,string[]>={cancel:['accepted','queued','running','waiting_approval','waiting_clarification'],retry:['failed','cancelled'],recover:['failed'],resume:['waiting_approval','waiting_clarification','failed'],continue:['failed','succeeded'],steer:['running','waiting_approval','waiting_clarification'],approval:['waiting_approval'],clarification:['waiting_clarification']};return allowed[action]?.includes(selected.state)??false}
  function setWorkspace(next:'user'|'admin'){workspace=next;selected=null;socket?.close();view=next==='admin'?'overview':'jobs';offset=0;if(next==='admin')loadAdmin('overview');else refreshJobs()}
  function changeView(next: typeof view){view=next;selected=null;socket?.close();if(next==='jobs')refreshJobs();if(next==='submit'){artifactOffset=0;loadAvailableArtifacts();}if(next==='overview'||next==='tenants'||next==='users')loadAdmin(next)}
  onDestroy(()=>{socket?.close();if(reconnect)clearTimeout(reconnect)});
</script>

{#if !jwt}
  <main class="signin"><section class="signin-card"><div class="brand-mark">AA</div><p class="eyebrow">Internal operations</p><h1>Service Console</h1><p class="muted">Test the Adaptive Agent backend with your scoped service token.</p><form on:submit|preventDefault={()=>signIn()}><label for="token">JSON Web Token</label><textarea id="token" bind:value={tokenInput} rows="5" spellcheck="false" placeholder="Paste JWT" required></textarea><button class="primary wide" type="submit">Open console <span>→</span></button></form><p class="security">Token is held in memory only and is cleared on refresh. Claims are decoded locally and are not validated by this UI.</p>{#if error}<div class="alert error">{error}</div>{/if}</section></main>
{:else}
  <div class="shell">
    <header><button class="logo" aria-label="Service Console home" on:click={()=>changeView(workspace==='admin'?'overview':'jobs')}><span>AA</span><strong>Service Console</strong></button><div class="context"><span><small>TENANT</small>{String(claims?.tenant_id||claims?.tenantId||'unknown')}</span><span><small>USER</small>{String(claims?.sub||claims?.user_id||'unknown')}</span><button class="ghost" on:click={signOut}>Clear token</button></div></header>
    <aside><nav aria-label="Workspace"><p>Workspace</p><button class:active={workspace==='user'} on:click={()=>setWorkspace('user')}>User operations</button>{#if isAdmin()}<button class:active={workspace==='admin'} on:click={()=>setWorkspace('admin')}>Platform admin</button>{/if}</nav><nav aria-label="Sections"><p>Explore</p>{#if workspace==='user'}<button class:active={view==='jobs'} on:click={()=>changeView('jobs')}>Jobs</button><button class:active={view==='submit'} on:click={()=>changeView('submit')}>New submission</button>{:else}<button class:active={view==='overview'} on:click={()=>changeView('overview')}>Overview</button><button class:active={view==='jobs'} on:click={()=>changeView('jobs')}>Cross-tenant jobs</button><button class:active={view==='tenants'} on:click={()=>changeView('tenants')}>Tenants</button><button class:active={view==='users'} on:click={()=>changeView('users')}>Users</button>{/if}</nav><div class="rolebox"><small>ACTIVE ROLES</small>{#each roles() as role}<span>{role}</span>{/each}</div></aside>
    <main class="content">
      {#if workspace==='admin'}<div class="audit-banner"><strong>Audited workspace</strong><span>Every administrative action is recorded with your identity and tenant context.</span></div>{/if}
      {#if error}<div class="alert error" role="alert">{error}<button aria-label="Dismiss error" on:click={()=>error=''}>×</button></div>{/if}{#if notice}<div class="alert success" role="status">{notice}<button aria-label="Dismiss notification" on:click={()=>notice=''}>×</button></div>{/if}
      {#if view==='jobs'}
        <div class="page-title"><div><p class="eyebrow">{workspace==='admin'?'Platform scope':'Your workspace'}</p><h1>{selected?'Job inspection':'Jobs'}</h1></div>{#if selected}<button class="ghost" on:click={()=>{selected=null;socket?.close()}}>← All jobs</button>{:else if workspace==='user'}<button class="primary" on:click={()=>changeView('submit')}>+ New submission</button>{/if}</div>
        {#if !selected}<section class="panel"><div class="toolbar">{#if workspace==='admin'}<label>Tenant<input bind:value={tenantFilter} placeholder="All tenants" /></label><label>Owner<input bind:value={ownerFilter} placeholder="All users" /></label>{/if}<label>Kind<select bind:value={kindFilter} on:change={()=>{offset=0;refreshJobs()}}><option value="">All kinds</option>{#each kinds as kind}<option>{kind}</option>{/each}</select></label><label>State<select bind:value={stateFilter} on:change={()=>{offset=0;refreshJobs()}}><option value="">All states</option>{#each states as state}<option>{state}</option>{/each}</select></label><button class="ghost" on:click={()=>{offset=0;refreshJobs()}} disabled={loading}>{loading?'Loading…':'Apply filters'}</button></div><div class="table-wrap"><table><thead><tr>{#if workspace==='admin'}<th>Tenant</th>{/if}<th>Job</th><th>Kind</th><th>State</th><th>Updated</th><th></th></tr></thead><tbody>{#each jobs as job}<tr><td class:hidden={workspace!=='admin'}>{job.tenantId}</td><td><button class="job-link" on:click={()=>selectJob(job)}>{job.id}</button></td><td>{job.kind}</td><td><span class="state" data-state={job.state}>{job.state}</span></td><td>{when(job.updatedAt)}</td><td><button class="row-arrow" aria-label={`Inspect ${job.id}`} on:click={()=>selectJob(job)}>→</button></td></tr>{:else}<tr><td colspan={workspace==='admin'?6:5} class="empty">No jobs match these filters.</td></tr>{/each}</tbody></table></div><div class="pager"><span>{total?`${offset+1}–${Math.min(offset+limit,total)} of ${total}`:'0 jobs'}</span><div><button disabled={offset===0} on:click={()=>{offset=Math.max(0,offset-limit);refreshJobs()}}>Previous</button><button disabled={offset+limit>=total} on:click={()=>{offset+=limit;refreshJobs()}}>Next</button></div></div></section>
        {:else}<div class="detail-grid"><section class="panel summary"><div class="summary-head"><div><span class="state" data-state={selected.state}>{selected.state}</span><h2>{selected.id}</h2><p>{selected.kind} · updated {when(selected.updatedAt)}</p></div><span class:live={socketState==='live'} class="connection">● {socketState}</span></div><dl><div><dt>Tenant</dt><dd>{selected.tenantId}</dd></div><div><dt>Owner</dt><dd>{selected.ownerUserId}</dd></div><div><dt>Session</dt><dd>{selected.sessionId}</dd></div><div><dt>Coordinator run</dt><dd>{selected.coordinatorRunId||'—'}</dd></div><div><dt>Created</dt><dd>{when(selected.createdAt)}</dd></div><div><dt>Command version</dt><dd>{selected.processedCommandVersion} / {selected.commandVersion}</dd></div></dl></section>
          <section class="panel controls"><h3>Available operations</h3><div class="button-row">{#each ['cancel','retry','recover','resume','continue'] as action}{#if controlAllowed(action)}<button on:click={()=>control(action)}>{action}</button>{/if}{/each}</div>{#if controlAllowed('steer')||controlAllowed('clarification')}<label>Operator response<input bind:value={controlText} placeholder="Enter guidance or clarification" /></label><div class="button-row">{#if controlAllowed('steer')}<button on:click={()=>control('steer',{guidance:controlText})} disabled={!controlText}>Steer</button>{/if}{#if controlAllowed('clarification')}<button on:click={()=>control('clarification',{answer:controlText})} disabled={!controlText}>Clarify</button>{/if}</div>{/if}{#if controlAllowed('approval')}<div class="button-row"><button on:click={()=>control('approval',{approved:true})}>Approve</button><button class="danger" on:click={()=>control('approval',{approved:false})}>Deny</button></div>{/if}{#if !['accepted','queued','running','waiting_approval','waiting_clarification','failed','cancelled','succeeded'].includes(selected.state)}<p class="empty">No control is valid in the current state.</p>{/if}</section>
          <section class="panel span"><div class="section-head"><h3>Event timeline <span>{events.length}</span></h3><button class="ghost" on:click={replay}>HTTP replay</button></div><ol class="timeline">{#each [...events].reverse() as event}<li><span class="sequence">#{event.sequence}</span><div><strong>{event.type||'event'}</strong><time>{when(event.occurredAt||event.timestamp)}</time><pre>{fmt(event.data??event)}</pre></div></li>{:else}<li class="empty">No events have been published.</li>{/each}</ol></section>
          <section class="panel"><h3>Request & profile pins</h3><h4>Request</h4><pre>{fmt(selected.request)}</pre><h4>Profiles</h4><pre>{fmt(selected.profiles)}</pre></section><section class="panel"><h3>Outcome</h3><h4>Result</h4><pre>{fmt(selected.result??null)}</pre><h4>Error</h4><pre>{fmt(selected.error??null)}</pre></section>
          <section class="panel span"><h3>Artifacts <span>{artifacts.length}</span></h3><div class="artifact-list">{#each artifacts as artifact}<div><span class="file">{artifact.filename}</span><small>{artifact.mediaType} · {artifact.byteSize.toLocaleString()} bytes · {artifact.status}</small>{#if workspace==='user'&&artifact.status==='available'}<button on:click={()=>api.download(selected!.id,artifact).catch(fail)}>Download</button>{:else if workspace==='user'&&artifact.status==='quarantined'}<button class="danger" on:click={()=>downloadQuarantined(artifact).catch(fail)}>Download quarantined file</button>{/if}</div>{:else}<p class="empty">No artifact metadata.</p>{/each}</div></section>
          {#if workspace==='admin'}<section class="panel"><h3>Run links</h3><pre>{fmt(runLinks)}</pre></section><section class="panel"><h3>Audit trail</h3><pre>{fmt(audit)}</pre></section>{/if}
          <section class="panel span diagnostics"><button class="disclosure" aria-expanded={diagnostics} on:click={()=>diagnostics=!diagnostics}>Raw JSON diagnostics <span>{diagnostics?'−':'+'}</span></button>{#if diagnostics}<pre>{fmt({job:selected,events,artifacts,runLinks,audit})}</pre>{/if}</section></div>{/if}
      {:else if view==='submit'}
        <div class="page-title"><div><p class="eyebrow">User workspace</p><h1>Compose submission</h1></div></div><form class="panel composer" on:submit|preventDefault={submit}><div class="kind-tabs" role="radiogroup" aria-label="Workload type">{#each kinds as kind}<button type="button" role="radio" aria-checked={submitKind===kind} class:active={submitKind===kind} on:click={()=>submitKind=kind}>{kind}</button>{/each}</div><div class="form-grid"><label>{submitKind==='swarm'?'Coordinator':submitKind==='orchestration'?'Orchestrator':'Agent'}<select bind:value={primaryAgent} required>{#each agents.filter(a=>!a.allowedWorkloads.length||a.allowedWorkloads.includes(submitKind)) as agent}<option value={agent.id}>{agent.id} · v{agent.version}</option>{/each}</select></label><label>Idempotency key <span>optional</span><input bind:value={idempotencyKey} placeholder="e.g. console-test-001" /></label></div>{#if submitKind==='swarm'||submitKind==='orchestration'}<fieldset><legend>{submitKind==='swarm'?'Worker agents':'Participating agents'}</legend><div class="checks">{#each agents.filter(a=>a.id!==primaryAgent) as agent}<label><input type="checkbox" checked={otherAgents.includes(agent.id)} on:change={()=>toggleAgent(agent.id)} /> {agent.id}<small>v{agent.version}</small></label>{/each}</div></fieldset>{/if}<label>{submitKind==='chat'?'Message':submitKind==='run'?'Goal':'Objective'}<textarea bind:value={prompt} rows="6" required placeholder="Describe the backend workload precisely"></textarea></label><fieldset><legend>Input artifacts <span>optional · {selectedFileRefs.length} selected</span></legend><div class="section-head"><small>Select explicit artifacts to disambiguate duplicate filenames.</small><button class="ghost" type="button" on:click={loadAvailableArtifacts} disabled={loadingArtifacts}>{loadingArtifacts?'Loading…':'Refresh'}</button></div><div class="checks">{#each availableArtifacts as artifact}<label><input type="checkbox" checked={selectedFileRefs.includes(artifact.id)} on:change={()=>toggleFileRef(artifact.id)} /> {artifact.filename}<small>{artifact.byteSize.toLocaleString()} bytes · {artifact.id.slice(0,8)}</small></label>{:else}<p class="empty">No available artifacts owned by this user.</p>{/each}</div><div class="pager"><span>{artifactTotal?`${artifactOffset+1}–${Math.min(artifactOffset+artifactLimit,artifactTotal)} of ${artifactTotal}`:'0 artifacts'}</span><div><button type="button" disabled={artifactOffset===0||loadingArtifacts} on:click={()=>{artifactOffset=Math.max(0,artifactOffset-artifactLimit);loadAvailableArtifacts()}}>Previous</button><button type="button" disabled={artifactOffset+artifactLimit>=artifactTotal||loadingArtifacts} on:click={()=>{artifactOffset+=artifactLimit;loadAvailableArtifacts()}}>Next</button></div></div></fieldset>{#if submitKind==='run'}<label>Run input JSON <span>optional</span><textarea class="code" bind:value={jsonInput} rows="7" spellcheck="false" placeholder={'{"key":"value"}'}></textarea></label>{/if}{#if submitKind==='chat'}<label>Conversation ID <span>optional</span><input bind:value={conversationId} /></label>{/if}<div class="submit-row"><p>Submits directly to <code>/v1/jobs/{submitKind}</code></p><button class="primary" type="submit">Submit {submitKind} →</button></div></form>
      {:else if view==='overview'}<div class="page-title"><div><p class="eyebrow">Platform administration</p><h1>Operational overview</h1></div><button class="ghost" on:click={()=>loadAdmin('overview')}>↻ Refresh</button></div><section class="metric-grid">{#each Object.entries((overview as Record<string,unknown>)||{}) as [key,value]}<article><small>{key.replaceAll('_',' ')}</small>{#if typeof value==='object'}<pre>{fmt(value)}</pre>{:else}<strong>{String(value)}</strong>{/if}</article>{/each}</section>
      {:else}<div class="page-title"><div><p class="eyebrow">Platform administration</p><h1>{view==='tenants'?'Tenants':'Users'}</h1></div><button class="ghost" on:click={()=>loadAdmin(view as 'tenants'|'users')}>↻ Refresh</button></div><section class="panel">{#if view==='users'}<div class="toolbar"><label>Tenant<input bind:value={userTenantFilter} placeholder="All tenants" /></label><button class="ghost" on:click={()=>loadAdmin('users')}>Apply filter</button></div>{/if}<div class="table-wrap"><table><thead><tr>{#each Object.keys(((view==='tenants'?tenants:users)[0] as Record<string,unknown>)||{}) as key}<th>{key}</th>{/each}</tr></thead><tbody>{#each view==='tenants'?tenants:users as row}<tr>{#each Object.values(row as Record<string,unknown>) as value}<td>{typeof value==='object'?fmt(value):String(value??'—')}</td>{/each}</tr>{:else}<tr><td class="empty">No records returned.</td></tr>{/each}</tbody></table></div></section>{/if}
    </main>
  </div>
{/if}
